PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?club(COUNT(*) AS ?count) WHERE {
  VALUES ?club {
    wd:Q2521385 wd:Q249679 wd:Q2272176
  }
  ?season wdt:P1344 ?club ; wdt:P1352 ?position .
  {
    SELECT ?season(MAX(?pos) AS ?maxPos) WHERE {
      ?season wdt:P1352 ?pos
    }
    GROUP BY ?season
  }
  FILTER(?position = ?maxPos)
}
GROUP BY ?club

